// Renderizador markdown -> HTML robusto: agrupa listas en <ul>, respeta encabezados,
// convierte enlaces markdown y URLs sueltas, y envuelve el texto en parrafos.
function mdToHtml(md) {
  const lines = String(md == null ? '' : md).split(/\r?\n/);
  const inline = (t) => escHtml(t)
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/\[([^\]]+)\]\((https?:\/\/[^)\s]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
    .replace(/(^|[^"'>=(])((?:https?:\/\/)[^\s<)]+)/g, '$1<a href="$2" target="_blank" rel="noopener">$2</a>');
  let html = '';
  let inList = false;
  const closeList = () => { if (inList) { html += '</ul>'; inList = false; } };
  for (const raw of lines) {
    const line = raw.replace(/\s+$/, '');
    if (/^\s*[-*]\s+/.test(line)) {
      if (!inList) { html += '<ul style="margin:8px 0 8px 18px;padding:0">'; inList = true; }
      html += '<li style="margin:4px 0">' + inline(line.replace(/^\s*[-*]\s+/, '')) + '</li>';
      continue;
    }
    closeList();
    if (/^###\s+/.test(line)) { html += '<h3 style="margin:18px 0 6px">' + inline(line.replace(/^###\s+/, '')) + '</h3>'; continue; }
    if (/^##\s+/.test(line)) { html += '<h2 style="margin:22px 0 8px;border-bottom:1px solid #e5e7eb;padding-bottom:4px">' + inline(line.replace(/^##\s+/, '')) + '</h2>'; continue; }
    if (/^#\s+/.test(line)) { html += '<h1 style="margin:8px 0 12px">' + inline(line.replace(/^#\s+/, '')) + '</h1>'; continue; }
    if (line.trim() === '') { continue; }
    html += '<p style="margin:8px 0;line-height:1.55">' + inline(line) + '</p>';
  }
  closeList();
  return html;
}

