  const puntos = arr(ds.datos).filter(p => p && p.etiqueta != null && isFinite(Number(p.valor)) && p.fuente_url);
  if (puntos.length < 2) continue;
  const tipo = ['lineas', 'pastel', 'barras'].indexOf(ds.tipo_grafico) >= 0 ? ds.tipo_grafico : 'barras';
  const chartType = tipo === 'lineas' ? 'line' : (tipo === 'pastel' ? 'pie' : 'bar');
  const labels = puntos.map(p => String(p.etiqueta).slice(0, 40));
  const values = puntos.map(p => Number(p.valor));
  const cfg = {
    type: chartType,
    data: { labels: labels, datasets: [{ label: String(ds.titulo || prev.tema).slice(0, 80), data: values, backgroundColor: chartType === 'bar' ? paleta[0] : paleta.slice(0, values.length) }] },
    options: { plugins: { title: { display: true, text: String(ds.titulo || '').slice(0, 90) }, legend: { display: chartType !== 'bar' } } }
  };
  const url = 'https://quickchart.io/chart?w=620&h=360&bkg=white&c=' + encodeURIComponent(JSON.stringify(cfg));
  graficos.push({ titulo: String(ds.titulo || ''), tipo: tipo, url: url, fuente: String(ds.fuente_principal || puntos[0].fuente_url) });
  datasetsValidos.push({ titulo: String(ds.titulo || ''), descripcion: String(ds.descripcion || ''), tipo_grafico: tipo, fuente_principal: String(ds.fuente_principal || puntos[0].fuente_url), datos: puntos, quickchart_url: url });
}

